def binary_search_recursive(arr, target, left=0, right=None):
    """递归实现的二分查找算法

    Args:
        arr (list): 已排序的数组
        target: 要查找的目标值
        left (int): 左边界索引
        right (int): 右边界索引

    Returns:
        int: 目标值的索引，未找到返回-1
    """
    if right is None:
        right = len(arr) - 1

    # 基础情况：未找到
    if left > right:
        return -1

    mid = (left + right) // 2

    if arr[mid] == target:
        return mid
    elif arr[mid] > target:
        return binary_search_recursive(arr, target, left, mid - 1)
    else:
        return binary_search_recursive(arr, target, mid + 1, right)

